const items = $input.all();
const results = [];

for (const item of items) {
  try {
    const msg = item.json?.choices?.[0]?.message || {};

    let raw =
      msg.content ||
      msg.reasoning_content ||
      '';

    raw = raw.trim();

    const match = raw.match(/\{[\s\S]*\}/);

    if (!match) continue;

    const parsed = JSON.parse(match[0]);

    if (!parsed.offers_relocation) continue;

    if (
      parsed.confidence &&
      parsed.confidence.toLowerCase() === 'low'
    ) {
      continue;
    }

    results.push({
      json: {
        url:
          item.json.body?.url ||
          item.json.url ||
          '',

        title:
          item.json.body?.title ||
          item.json.title ||
          '',

        company:
          item.json.body?.company ||
          item.json.company ||
          '',

        location:
          item.json.body?.location ||
          item.json.location ||
          '',

        description:
          item.json.body?.description ||
          item.json.description ||
          '',

        relocation_signals:
          (parsed.signals || []).join(', '),

        relocation_confidence:
          parsed.confidence || 'medium'
      }
    });

  } catch (e) {
    console.log('Parse error:', e.message);
  }
}

return results;

