// Extract cover letter and assemble final row.
// includeInputData: true means job fields are merged into $json alongside LLM response.
const items = $input.all();
const results = [];

for (const item of items) {
  if (!item?.json) continue;
  try {
    const coverLetter = (item.json?.choices?.[0]?.message?.content || '').trim();
    if (!coverLetter) continue;

    results.push({
      json: {
        date:                  new Date().toISOString().split('T')[0],
        company:               item.json.company               || '',
        title:                 item.json.title                 || '',
        location:              item.json.location              || '',
        url:                   item.json.url                   || '',
        relocation_signals:    item.json.relocation_signals    || '',
        relocation_confidence: item.json.relocation_confidence || '',
        cover_letter:          coverLetter,
        status:                'Not Applied'
      }
    });
  } catch (e) { continue; }
}

return results;
